abstract class Database(val name: String) {
    abstract fun connect(): Boolean
    abstract fun disconnect()

    fun status() {
        val connected = connect()
        println("Database '$name' connected: $connected")
        disconnect()
    }
}

class MySQLDatabase(name: String) : Database(name) {
    override fun connect(): Boolean {
        println("Connecting to MySQL: $name")
        return true
    }
    override fun disconnect() {
        println("Disconnecting from MySQL: $name")
    }
}

fun main() {
    val db = MySQLDatabase("mydb")
    db.status()
}
